def perceive(data):
    if isinstance(data, dict):
        fields = {str(k).strip().lower(): v for k, v in data.items()}
    else:
        fields = {}
        for line in str(data).splitlines():
            if ":" in line:
                k, v = line.split(":", 1)
                fields[k.strip().lower()] = v.strip()
    out = {}
    exhibits = fields.get("exhibits")
    if exhibits is not None:
        try:
            n = int(exhibits)
        except (ValueError, TypeError):
            n = 0
        out["evidence_score"] = max(0, min(100, 10 * n))
    return out
